/**
 * Formatea una fecha como DD/MM/YYYY HH:MM:SS
 * @param {string|Date} value
 * @returns {string}
 */
export const formatoFechaHora = (value) => {
  if (value === null) return ''
  const fecha = new Date(new Date(value).toLocaleString('en-US', { timeZone: 'UTC' }))
  return (
    fecha.getDate().toString().padStart(2, 0) +
    '/' +
    (fecha.getMonth() + 1).toString().padStart(2, 0) +
    '/' +
    fecha.getFullYear() +
    ' ' +
    fecha.getHours().toString().padStart(2, 0) +
    ':' +
    fecha.getMinutes().toString().padStart(2, 0) +
    ':' +
    fecha.getSeconds().toString().padStart(2, 0)
  )
}

/**
 * Formatea una fecha como DD/MM/YYYY
 * @param {string|Date|null} value
 * @returns {string}
 */
export const formatoFecha = (value = null) => {
  if (value === null) return ''
  const fecha = new Date(new Date(value).toLocaleString('en-US', { timeZone: 'UTC' }))
  return (
    fecha.getDate().toString().padStart(2, 0) +
    '/' +
    (fecha.getMonth() + 1).toString().padStart(2, 0) +
    '/' +
    fecha.getFullYear()
  )
}

/**
 * Formatea una fecha como "DD NombreMes YYYY" en español
 * @param {string|Date} value
 * @returns {string}
 */
export const formatoFechaEstadoCuenta = (value) => {
  if (value === null) return ''
  const fecha = new Date(new Date(value).toLocaleString('en-US', { timeZone: 'UTC' }))
  const M = fecha.toLocaleString('es-ES', { timeZone: 'UTC', month: 'long' })
  const Mes = M.charAt(0).toUpperCase() + M.slice(1)
  return fecha.getDate() + ' ' + Mes + ' ' + fecha.getFullYear()
}

/**
 * Convierte "DD/MM/YYYY" a "YYYY-MM-DD"
 * @param {string} fechaStr
 * @returns {string}
 */
export const fechaInternacional = (fechaStr) => {
  const [dia, mes, year] = fechaStr.split('/')
  return `${year}-${mes}-${dia}`
}

/**
 * Retorna la fecha de expiración como "MM/YY"
 * @param {string|null} dateStr
 * @returns {string}
 */
export const fechaExpiracion = (dateStr) => {
  if (dateStr === null) return ''
  const fecha = new Date(new Date(dateStr).toLocaleString('en-US', { timeZone: 'UTC' }))
  const month = (fecha.getMonth() + 1).toString().padStart(2, '0')
  const year = fecha.getFullYear() % 100
  return `${month}/${year}`
}
